import React from 'react';
import { useParams } from 'react-router-dom';
import Markdown from 'react-markdown';
import remarkHtml from 'remark-html';
const ModulePage = () => {
	const [markdownContent, setMarkdownContent] = React.useState('');

	const fetchMarkdownContent = async () => {
		const response = await fetch('/modules/machine-learning/index.md');
		const markdownContent = await response.text();
		setMarkdownContent(markdownContent);
	};

	React.useEffect(() => {
		fetchMarkdownContent();
	}, []);

	return (
		<div style={{}}>
			<Markdown remarkPlugins={[remarkHtml]}>
				## This is a heading * This is a list item 
				![This is an image](https://example.com/image.png) 
				| This is a table | This is another column |
				|---|---|
				| Row 1 | Value 1 | | Row 2 | Value 2 |
			</Markdown>
		</div>
	);
};

export default ModulePage;
